SELECT SA2_2018_name, area
FROM SA2_2018
WHERE population > 20000;

SELECT region_name, total_population
FROM regions
WHERE total_population = (SELECT MAX(population) FROM TA_2018);

SELECT u.user_id, u.user_name, u.role 
FROM users u
LEFT JOIN roles r ON u.role = r.role_name;

SELECT *,
    ROW_NUMBER() OVER (ORDER BY partially_vaccinated_uptake DESC) as rank
FROM vaccination_data;

SELECT contact_email
FROM district_health_boards
WHERE dhb_name = 'Northland';

SELECT population 
FROM vaccination_data 
WHERE vaccination_id < 100;

SELECT region_id, region_name, population_density
FROM regions
WHERE population_density > (
  SELECT AVG(fully_vaccinated) 
  FROM vaccination_data
);
